"use strict";

const fs = require("fs");
const path = require("path");
const cp = require("child_process");

const ROOT = process.cwd();
const BACKUP_ROOT = path.join(ROOT, "backups", "v18_2_room_ultra_" + new Date().toISOString().replace(/[:.]/g, "-").replace("T", "_").slice(0, 19));

function abs(rel) { return path.join(ROOT, rel); }
function exists(rel) { return fs.existsSync(abs(rel)); }
function read(rel) { return fs.readFileSync(abs(rel), "utf8"); }
function write(rel, text) { fs.mkdirSync(path.dirname(abs(rel)), { recursive: true }); fs.writeFileSync(abs(rel), text, "utf8"); }
function log(msg) { console.log(msg); }
function warn(msg) { console.log("[AVISO] " + msg); }
function fail(msg) { console.error("[ERRO] " + msg); process.exitCode = 1; }

function backup(rel) {
  if (!exists(rel)) return;
  const dst = path.join(BACKUP_ROOT, rel);
  fs.mkdirSync(path.dirname(dst), { recursive: true });
  fs.copyFileSync(abs(rel), dst);
}

function backupAndWrite(rel, text) {
  backup(rel);
  write(rel, text);
  log("[OK] Atualizado: " + rel);
}

function parseJson(rel, fallback) {
  try { return JSON.parse(read(rel)); } catch { return fallback; }
}

function runCheck(rel) {
  if (!exists(rel)) return true;
  const result = cp.spawnSync(process.execPath, ["--check", abs(rel)], { encoding: "utf8" });
  if (result.status !== 0) {
    console.error(result.stdout || "");
    console.error(result.stderr || "");
    fail("node --check falhou: " + rel);
    return false;
  }
  log("[OK] node --check " + rel);
  return true;
}

function insertBefore(text, marker, insert) {
  if (text.includes(insert.trim().slice(0, 80))) return text;
  const idx = text.indexOf(marker);
  if (idx < 0) {
    warn("Marcador não encontrado: " + marker);
    return text + "\n\n" + insert;
  }
  return text.slice(0, idx) + insert + text.slice(idx);
}

function replaceMarked(text, begin, end, block) {
  const start = text.indexOf(begin);
  const finish = text.indexOf(end, start);
  if (start >= 0 && finish >= 0) {
    return text.slice(0, start) + block + text.slice(finish + end.length);
  }
  return null;
}

function patchMain() {
  const rel = "main.js";
  if (!exists(rel)) return warn("main.js não encontrado; pulando IPC da Room.");
  let text = read(rel);

  if (!text.includes("let roomWin")) {
    if (text.includes("let mainWin = null; let avatarWin = null;")) text = text.replace("let mainWin = null; let avatarWin = null;", "let mainWin = null; let avatarWin = null; let roomWin = null;");
    else text = text.replace("let mainWin = null;", "let mainWin = null; let roomWin = null;");
  }

  const block = "// NOELLE_ROOM_V18_2_BEGIN\nfunction roomCatalogPath() {\n  return path.join(ASSETS_DIR, \"room_manifest.json\");\n}\nfunction roomLayoutDevPath() {\n  return path.join(ASSETS_DIR, \"room_layout.json\");\n}\nfunction roomLayoutUserPath() {\n  return path.join(getUserDataSafe(), \"rooms\", \"room_layout.json\");\n}\nfunction readRoomJson(file, fallback) {\n  try {\n    if (!fs.existsSync(file)) return fallback;\n    const text = fs.readFileSync(file, \"utf8\").trim();\n    return text ? JSON.parse(text) : fallback;\n  } catch {\n    return fallback;\n  }\n}\nfunction inferRoomManifestFromItems() {\n  const itemManifest = readRoomJson(path.join(ASSETS_DIR, \"item_manifest.json\"), []);\n  const list = Array.isArray(itemManifest) ? itemManifest : Array.isArray(itemManifest.items) ? itemManifest.items : [];\n  const roomIds = /desk|piano|chair|cadeira|mesa|table|bed|sofa|monitor|lamp|shelf|estante|room|floor/i;\n  return list.filter((item) => {\n    const hay = [item.id, item.label, item.file, item.category, item.kind].join(\" \");\n    return item.kind === \"room_item\" || item.category === \"scene_prop\" || item.category === \"furniture\" || roomIds.test(hay);\n  }).map((item) => ({\n    id: item.id,\n    label: item.label || item.id,\n    file: item.file,\n    kind: \"room_item\",\n    category: item.category || \"furniture\",\n    placement: { surface: \"floor\", snap: true, rotateStepDeg: 15, canCollide: true, targetSize: item.id === \"grand_piano\" ? 1.35 : 1.0 }\n  }));\n}\nfunction scanRoomCatalog() {\n  const raw = readRoomJson(roomCatalogPath(), null);\n  const list = Array.isArray(raw) ? raw : Array.isArray(raw?.items) ? raw.items : inferRoomManifestFromItems();\n  return list.filter(Boolean);\n}\nfunction finiteRoomNumber(value, fallback = 0) {\n  const n = Number(value);\n  return Number.isFinite(n) ? n : fallback;\n}\nfunction safeRoomVec3(value, fallback) {\n  if (!Array.isArray(value)) return [...fallback];\n  return [finiteRoomNumber(value[0], fallback[0]), finiteRoomNumber(value[1], fallback[1]), finiteRoomNumber(value[2], fallback[2])];\n}\nfunction sanitizeRoomLayout(layout) {\n  return {\n    version: 1,\n    roomId: String(layout?.roomId || \"default_room\").replace(/[^a-zA-Z0-9_-]/g, \"_\"),\n    grid: layout?.grid || { size: 0.25, enabled: true },\n    items: Array.isArray(layout?.items) ? layout.items.map((item) => ({\n      uid: String(item.uid || \"\").slice(0, 100),\n      itemId: String(item.itemId || \"\").slice(0, 100),\n      position: safeRoomVec3(item.position, [0, 0, 0]),\n      rotationDeg: safeRoomVec3(item.rotationDeg, [0, 0, 0]),\n      scale: safeRoomVec3(item.scale, [1, 1, 1]).map((v) => Math.max(0.001, v)),\n      locked: !!item.locked\n    })).filter((item) => item.uid && item.itemId) : []\n  };\n}\nfunction loadRoomLayoutFile() {\n  const user = roomLayoutUserPath();\n  const dev = roomLayoutDevPath();\n  return sanitizeRoomLayout(readRoomJson(user, readRoomJson(dev, { version: 1, roomId: \"default_room\", grid: { size: 0.25, enabled: true }, items: [] })));\n}\nfunction saveRoomLayoutFile(layout) {\n  const safe = sanitizeRoomLayout(layout || {});\n  const user = roomLayoutUserPath();\n  ensureDir(path.dirname(user));\n  const tmp = user + \".tmp\";\n  fs.writeFileSync(tmp, JSON.stringify(safe, null, 2), \"utf8\");\n  fs.renameSync(tmp, user);\n  if (!app.isPackaged) {\n    try {\n      const devTmp = roomLayoutDevPath() + \".tmp\";\n      fs.writeFileSync(devTmp, JSON.stringify(safe, null, 2), \"utf8\");\n      fs.renameSync(devTmp, roomLayoutDevPath());\n    } catch {}\n  }\n  return safe;\n}\nfunction createRoomWindow({ show = true } = {}) {\n  if (roomWin && !roomWin.isDestroyed()) {\n    if (show) roomWin.show();\n    roomWin.focus();\n    return roomWin;\n  }\n  roomWin = new BrowserWindow({\n    width: 1280,\n    height: 820,\n    minWidth: 960,\n    minHeight: 650,\n    title: \"Noelle Room\",\n    icon: typeof getAppIconPath === \"function\" ? getAppIconPath() : undefined,\n    backgroundColor: \"#080711\",\n    autoHideMenuBar: true,\n    show: false,\n    webPreferences: {\n      preload: path.join(ROOT_DIR, \"preload.js\"),\n      contextIsolation: true,\n      nodeIntegration: false,\n      sandbox: false\n    }\n  });\n  roomWin.once(\"ready-to-show\", () => { if (show) roomWin.show(); });\n  roomWin.on(\"closed\", () => { roomWin = null; });\n  roomWin.loadFile(path.join(SRC_DIR, \"room.html\"));\n  return roomWin;\n}\n// NOELLE_ROOM_V18_2_END\n";
  const replaced = replaceMarked(text, "// NOELLE_ROOM_V18_2_BEGIN", "// NOELLE_ROOM_V18_2_END", block);
  if (replaced !== null) text = replaced;
  else text = insertBefore(text, "function createAvatarWindow", block);

  // Remove old room IPC blocks/lines, then add the V18.2 block once.
  text = text.replace(/\/\/ NOELLE_ROOM_IPC_V18_2_BEGIN[\s\S]*?\/\/ NOELLE_ROOM_IPC_V18_2_END/g, "");
  text = text.replace(/ipcMain\.handle\("room:(?:open|close|catalog|load-layout|save-layout)"[\s\S]*?\);\n?/g, "");
  text += "\n" + "// NOELLE_ROOM_IPC_V18_2_BEGIN\nipcMain.handle(\"room:open\", async () => { createRoomWindow({ show: true }); return { ok: true }; });\nipcMain.handle(\"room:close\", async () => { if (roomWin && !roomWin.isDestroyed()) roomWin.hide(); return { ok: true }; });\nipcMain.handle(\"room:catalog\", async () => ({ ok: true, items: scanRoomCatalog() }));\nipcMain.handle(\"room:load-layout\", async () => ({ ok: true, layout: loadRoomLayoutFile() }));\nipcMain.handle(\"room:save-layout\", async (_event, layout) => ({ ok: true, layout: saveRoomLayoutFile(layout || {}) }));\n// NOELLE_ROOM_IPC_V18_2_END\n";

  if (text.includes("Menu.buildFromTemplate([") && !text.includes("Abrir Room")) {
    text = text.replace("Menu.buildFromTemplate([", 'Menu.buildFromTemplate([{ label: "Abrir Room", click: () => createRoomWindow({ show: true }) },');
  }

  backupAndWrite(rel, text);
}

function patchPreload() {
  const rel = "preload.js";
  if (!exists(rel)) return warn("preload.js não encontrado; pulando noelleRoom.");
  let text = read(rel);

  const roomExpose = "\ncontextBridge.exposeInMainWorld(\"noelleRoom\", {\n  open: () => ipcRenderer.invoke(\"room:open\"),\n  close: () => ipcRenderer.invoke(\"room:close\"),\n  listCatalog: () => ipcRenderer.invoke(\"room:catalog\"),\n  loadLayout: () => ipcRenderer.invoke(\"room:load-layout\"),\n  saveLayout: (layout) => ipcRenderer.invoke(\"room:save-layout\", layout)\n});\n";
  if (!text.includes('exposeInMainWorld("noelleRoom"')) text += "\n" + roomExpose;

  backupAndWrite(rel, text);
}

